#include <stdio.h>

int main() {
    int numbers[] = {10, 20, 30, 40, 50};
    int *ptr = numbers; // equivalent to &numbers[0]

    printf("Initial pointer value (first element): %d\n", *ptr);

    // Demonstrating Pointer Arithmetic
    ptr++; // Moves pointer to next integer (adds sizeof(int) bytes)
    printf("After ptr++ (second element): %d\n", *ptr);

    ptr += 2; // Moves pointer forward by 2 more integers
    printf("After ptr += 2 (fourth element): %d\n", *ptr);

    // Calculating elements distance via subtraction
    int *start_ptr = numbers;
    printf("Distance between current and start: %ld elements\n", (ptr - start_ptr));

    // Accessing elements using pointer offset notation
    for(int i = 0; i < 5; i++) {
        printf("Element %d via pointer: %d\n", i, *(start_ptr + i));
    }

    return 0;
}

