#include <stdio.h>

// Callback comparisons for sorting/display systems
int ascending(int a, int b) {
    return a - b;
}

int descending(int a, int b) {
    return b - a;
}

// Generic function processing void pointers and function pointers
void processNumbers(void *arr, int size, int (*compare)(int, int)) {
    int *int_arr = (int*)arr; // Safe explicit cast from void*
    for(int i = 0; i < size - 1; i++) {
        for(int j = i + 1; j < size; j++) {
            if(compare(int_arr[i], int_arr[j]) > 0) {
                // Swap logic using pointers
                int temp = *(int_arr + i);
                *(int_arr + i) = *(int_arr + j);
                *(int_arr + j) = temp;
            }
        }
    }
}

int main() {
    int values[] = {45, 12, 89, 7, 54};
    int size = sizeof(values) / sizeof(values[0]);

    printf("Sorting ascending using callbacks:\n");
    processNumbers(values, size, ascending);
    for(int i = 0; i < size; i++) {
        printf("%d ", values[i]);
    }
    printf("\n");

    printf("Sorting descending using callbacks:\n");
    processNumbers(values, size, descending);
    for(int i = 0; i < size; i++) {
        printf("%d ", values[i]);
    }
    printf("\n");

    return 0;
}

