#include <stdio.h>
#include <string.h>

int genericSearch(void *arr, int size, size_t elemSize, void *target, int (*compare)(const void *, const void *)) {
    char *bytePtr = (char *)arr;
    for (int i = 0; i < size; i++) {
        if (compare(bytePtr + (i * elemSize), target) == 0) {
            return i; // Found at index
        }
    }
    return -1; // Not found
}

int intCompare(const void *a, const void *b) {
    return *(const int *)a - *(const int *)b;
}

int main() {
    int data[] = {10, 25, 54, 88, 92};
    int target = 88;
    int index = genericSearch(data, 5, sizeof(int), &target, intCompare);
    printf("Found at index: %d\n", index);
    return 0;
}
```

Consider this bug:
```c
int* getLocalAddress() {
    int x = 100;
    return &x;
}
```
Here, variable `x` is stored on the Stack frame of `getLocalAddress`. When the function finishes execution, its stack frame is destroyed/popped. The pointer returned now points to a deallocated stack block. Accessing this address in the caller leads to a dangling pointer with undefined values.

Solution: Use static variables (persisting on Data segment) or allocate memory on the Heap:
```c
int* getStaticAddress() {
    static int x = 100;
    return &x;
}
```

