#include <stdio.h>

void reverseArray(int *arr, int size) {
    int *left = arr;
    int *right = arr + size - 1;
    while (left < right) {
        int temp = *left;
        *left = *right;
        *right = temp;
        left++;
        right--;
    }
}

int main() {
    int arr[] = {1, 2, 3, 4, 5, 6};
    reverseArray(arr, 6);
    for(int i = 0; i < 6; i++) {
        printf("%d ", arr[i]);
    }
    return 0;
}
```

